<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Ubuntu Desktop Simulation</title>
    <style>
        :root {
            --bg-color: #1a1a1a;
            --taskbar-bg: #2d2d2d;
            --window-header: #3c3c3c;
            --text-color: #e0e0e0;
            --accent-blue: #4da6ff;
            --ubuntu-purple: #5c7cfa; /* Ubuntu-ish purple/blue */
            --border-color: #444;
        }

        * { box-sizing: border-box; user-select: none; }

        body, html {
            margin: 0; padding: 0; height: 100%; width: 100%; overflow: hidden;
            font-family: 'Ubuntu', 'Segoe UI', sans-serif;
            background-color: var(--bg-color);
            color: var(--text-color);
        }

        /* --- Desktop & Wallpaper --- */
        #desktop {
            width: 100vw; height: 100vh;
            position: relative;
            background: linear-gradient(135deg, #2b2b2b 0%, #1a1a1a 100%);
            /* Simple wallpaper pattern */
            background-image: 
                radial-gradient(circle at 10% 20%, rgba(77, 166, 255, 0.1) 0%, transparent 20%),
                radial-gradient(circle at 90% 80%, rgba(92, 124, 250, 0.1) 0%, transparent 20%);
        }

        /* --- Taskbar --- */
        #taskbar {
            position: absolute; bottom: 0; left: 0; right: 0;
            height: 48px;
            background-color: var(--taskbar-bg);
            border-top: 1px solid #555;
            display: flex; align-items: center; justify-content: space-between;
            padding: 0 10px;
            z-index: 1000;
        }

        .launcher {
            width: 48px; height: 48px;
            border-radius: 8px;
            display: flex; align-items: center; justify-content: center;
            cursor: pointer;
            transition: background 0.2s, transform 0.1s;
            font-size: 24px;
        }

        .launcher:hover { background-color: #444; }
        .launcher:active { transform: scale(0.95); }

        /* Icons (using simple unicode or CSS shapes for self-containment) */
        #open-files::before { content: "📁"; font-size: 28px; }
        #open-notepad::before { content: "📝"; font-size: 28px; }

        /* --- Window System --- */
        .window {
            position: absolute;
            background-color: #300a24; /* Ubuntu dark theme base */
            border-radius: 6px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: flex; flex-direction: column;
            min-width: 360px; min-height: 240px; /* Usable size requirement */
            overflow: hidden;
            border: 1px solid #555;
        }

        .window-header {
            height: 32px;
            background-color: var(--window-header);
            display: flex; align-items: center; justify-content: space-between;
            padding-left: 8px;
            cursor: default; /* Simplified for this task */
        }

        .win-title { font-size: 14px; font-weight: bold; color: #ccc; }

        .win-close {
            width: 20px; height: 20px;
            border-radius: 50%;
            background-color: transparent;
            color: #aaa;
            display: flex; align-items: center; justify-content: center;
            cursor: pointer;
            font-size: 14px;
        }

        .win-close:hover { background-color: #e81123; color: white; }

        .window-content {
            flex: 1;
            overflow: auto;
            position: relative;
        }

        /* --- Files App Specifics --- */
        #files-window { top: 50px; left: 50px; width: 600px; height: 400px; }

        #files-path-bar {
            background-color: #222; border-bottom: 1px solid #444;
            padding: 8px; font-family: monospace; color: #aaa;
            display: flex; align-items: center; gap: 5px;
        }

        .path-segment { cursor: pointer; color: var(--accent-blue); }
        .path-segment:hover { text-decoration: underline; }

        #files-list { padding: 10px; display: flex; flex-wrap: wrap; gap: 8px; }

        .fs-item {
            background-color: #444;
            padding: 6px 12px;
            border-radius: 4px;
            cursor: pointer;
            font-size: 13px;
            display: flex; align-items: center; gap: 6px;
            transition: background 0.1s;
        }

        .fs-item:hover { background-color: #555; }
        .fs-item.folder::before { content: "📁"; font-size: 14px; }
        .fs-item.file::before { content: "📄"; font-size: 14px; }

        #files-up-btn {
            background-color: var(--ubuntu-purple); color: white; border: none;
            padding: 5px 10px; border-radius: 4px; cursor: pointer; margin-bottom: 10px;
        }
        #files-up-btn:hover { opacity: 0.9; }

        /* --- Notepad App Specifics --- */
        #notepad-window { top: 60px; left: 60px; width: 500px; height: 350px; }

        #tabs-container {
            background-color: #2d2d2d;
            display: flex; align-items: center; padding-left: 5px;
            border-bottom: 1px solid #444;
            min-height: 30px;
        }

        .tab {
            background-color: #3c3c3c;
            color: #999;
            padding: 6px 12px;
            margin-right: 4px;
            border-radius: 4px 4px 0 0;
            font-size: 13px;
            cursor: pointer;
            max-width: 150px;
            white-space: nowrap;
            overflow: hidden; text-overflow: ellipsis;
        }

        .tab.active { background-color: #4a4a4a; color: white; border-bottom: 2px solid var(--ubuntu-purple); }

        #new-tab-btn {
            margin-left: auto;
            background: none; border: none; color: #999; cursor: pointer; font-size: 18px;
        }
        #new-tab-btn:hover { color: white; }

        #editor-container { flex: 1; position: relative; }

        #editor {
            width: 100%; height: 100%;
            background-color: #2b2b2b;
            color: #ddd;
            border: none; resize: none; outline: none; padding: 10px; font-family: monospace; font-size: 14px;
        }

    </style>
</head>
<body>

<div id="desktop">

    <!-- Files Window -->
    <div id="files-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="win-title">Files</span>
            <div class="win-close" onclick="toggleWindow('files-window')">✕</div>
        </div>
        <div class="window-content">
            <div id="files-path-bar"></div>
            <button id="files-up-btn" style="display:none;">⬆ Parent</button>
            <div id="files-list"></div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window" style="display:none;">
        <div class="window-header">
            <span class="win-title">Text Editor</span>
            <div class="win-close" onclick="toggleWindow('notepad-window')">✕</div>
        </div>
        <div class="window-content">
            <div id="tabs-container"></div>
            <div id="editor-container">
                <textarea id="editor" placeholder="Type here..."></textarea>
            </div>
        </div>
    </div>

</div>

<!-- Taskbar -->
<div id="taskbar">
    <div class="launcher" id="open-files" onclick="toggleWindow('files-window')">📁 Files</div>
    <div class="launcher" id="open-notepad" onclick="toggleWindow('notepad-window')">📝 Notepad</div>
</div>

<script>
    // --- State Management ---

    // Filesystem Data Structure (Static)
    const fsData = {
        '/': [
            { name: 'bin', type: 'dir' },
            { name: 'etc', type: 'dir' },
            { name: 'home', type: 'dir' },
            { name: 'usr', type: 'dir' },
            { name: 'var', type: 'dir' }
        ],
        '/bin': [
            { name: 'bash', type: 'file', content: '#!/bin/bash\necho "Hello World"' },
            { name: 'ls', type: 'file', content: 'echo "Listing files"' }
        ],
        '/etc': [
            { name: 'hosts', type: 'file', content: '127.0.0.1 localhost' },
            { name: 'passwd', type: 'file', content: 'root:x:0:0:root:/root:/bin/bash' }
        ],
        '/home': [
            { name: 'user', type: 'dir' }
        ],
        '/home/user': [
            { name: 'Documents', type: 'dir' },
            { name: 'Downloads', type: 'dir' },
            { name: 'Pictures', type: 'dir' },
            { name: 'todo.txt', type: 'file', content: '- Buy milk\n- Fix the bug' }
        ],
        '/home/user/Documents': [
            { name: 'resume.pdf', type: 'file', content: '[PDF Content Placeholder]' },
            { name: 'notes.md', type: 'file', content: '# My Notes\nThis is a markdown file.' }
        ],
        '/home/user/Downloads': [
            { name: 'image.png', type: 'file', content: '[Image Data]' }
        ],
        '/home/user/Pictures': [
            { name: 'vacation.jpg', type: 'file', content: '[Vacation Photo]' }
        ],
        '/usr': [
            { name: 'bin', type: 'dir' },
            { name: 'lib', type: 'dir' }
        ],
        '/usr/bin': [
            { name: 'python3', type: 'file', content: '#!/usr/bin/env python3\nprint("Python")' }
        ],
        '/var': [
            { name: 'log', type: 'dir' },
            { name: 'cache', type: 'dir' }
        ],
        '/var/log': [
            { name: 'syslog', type: 'file', content: 'Oct 24 10:00:00 server kernel: Started.' }
        ]
    };

    // --- Window Logic ---

    function toggleWindow(id) {
        const win = document.getElementById(id);
        if (win.style.display === 'none') {
            win.style.display = 'flex';
            // Focus logic could go here, but simple display toggle is requested.
        } else {
            win.style.display = 'none';
        }
    }

    // --- Files App Logic ---

    const filesPathEl = document.getElementById('files-path-bar');
    const filesListEl = document.getElementById('files-list');
    const filesUpBtn = document.getElementById('files-up-btn');

    let currentPath = '/';

    function renderFiles() {
        // Update Path Display
        const pathSegments = currentPath.split('/').filter(p => p);
        filesPathEl.innerHTML = '';

        if (pathSegments.length === 0) {
            filesPathEl.innerHTML = '<span class="path-segment">/</span>';
        } else {
            let html = '<span class="path-segment" onclick="navigateTo(\'/\')">/</span>';
            pathSegments.forEach(seg => {
                const fullPath = '/' + seg;
                html += `<span class="path-segment">${seg}</span>`;
            });
            filesPathEl.innerHTML = html;
        }

        // Get Children for current directory
        let children = [];
        if (currentPath === '/') {
            children = fsData['/'];
        } else {
            const parentDir = currentPath.substring(0, currentPath.lastIndexOf('/'));
            children = fsData[parentDir];
        }

        // Render List
        filesListEl.innerHTML = '';

        if (children.length === 0) {
            filesListEl.innerHTML = '<div style="color:#777; padding:10px;">Empty directory</div>';
            return;
        }

        children.forEach(item => {
            const div = document.createElement('div');
            div.className = `fs-item ${item.type}`;
            div.textContent = item.name;

            // Double click to enter folder
            div.ondblclick = () => {
                if (item.type === 'dir') {
                    navigateTo(currentPath + '/' + item.name);
                }
            };

            filesListEl.appendChild(div);
        });

        // Handle Up Button Visibility
        if (currentPath === '/') {
            filesUpBtn.style.display = 'none';
        } else {
            filesUpBtn.style.display = 'block';
            filesUpBtn.onclick = () => navigateTo(currentPath.substring(0, currentPath.lastIndexOf('/')));
        }
    }

    function navigateTo(path) {
        // Simple validation to prevent going up from root or into non-existent dirs in this static model
        if (fsData[path]) {
            currentPath = path;
            renderFiles();
        } else {
            console.log("Directory not found");
        }
    }

    // --- Notepad App Logic ---

    const tabsContainer = document.getElementById('tabs-container');
    const editor = document.getElementById('editor');

    // Tab State: Array of objects { id, title, content }
    let tabs = []; 
    let activeTabId = null;

    function initNotepad() {
        // Load from localStorage if available
        const savedTabs = localStorage.getItem('notepad_tabs');
        if (savedTabs) {
            tabs = JSON.parse(savedTabs);
        } else {
            // Create default tab on first load
            createTab('untitled-1', '');
        }

        renderNotepad();
    }

    function saveNotepad() {
        localStorage.setItem('notepad_tabs', JSON.stringify(tabs));
    }

    function createTab(title, content) {
        const id = 'tab-' + Date.now() + Math.random().toString(16).slice(2);
        tabs.push({ id, title, content });
        saveNotepad();
        renderNotepad();
    }

    function closeTab(id) {
        tabs = tabs.filter(t => t.id !== id);

        // If closing active tab, switch to another or create new one
        if (activeTabId === id) {
            const remainingTabs = tabs.filter(t => t.id !== id);
            if (remainingTabs.length > 0) {
                activeTabId = remainingTabs[0].id;
            } else {
                // No tabs left, create a new empty one
                createTab('untitled-new', '');
            }
        }

        saveNotepad();
        renderNotepad();
    }

    function switchTab(id) {
        activeTabId = id;
        renderNotepad();
    }

    function updateContent(content) {
        const tab = tabs.find(t => t.id === activeTabId);
        if (tab) {
            tab.content = content;
            saveNotepad();
        }
    }

    function renderNotepad() {
        // Render Tabs
        tabsContainer.innerHTML = '';

        tabs.forEach(tab => {
            const div = document.createElement('div');
            div.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
            div.textContent = tab.title;

            div.onclick = () => switchTab(tab.id);

            // Optional: Add close icon to tab? Not strictly required by prompt, but good UX. 
            // Prompt says "Clicking a launcher shows its window... Each window has a close button".
            // It doesn't explicitly ask for X on tabs, so we stick to basic click switching.

            tabsContainer.appendChild(div);
        });

        // Render Editor
        if (tabs.length > 0) {
            editor.value = tabs.find(t => t.id === activeTabId).content;
        } else {
            editor.value = '';
        }
    }

    // Event Listeners for Notepad
    editor.addEventListener('input', () => {
        if (activeTabId) updateContent(editor.value);
    });

    document.getElementById('new-tab-btn').addEventListener('click', () => {
        createTab('untitled-' + Date.now(), '');
    });

    // --- Initialization ---

    // Initialize Files App
    renderFiles();

    // Initialize Notepad App
    initNotepad();

</script>
</body>
</html>
